// Process and combine Trello data
const config = $input.first();
const updatedCards = $input.item(1);
const newCards = $input.item(2);

const activity = {
  date: config.json.todayDate,
  boardId: config.json.boardId,
  updatedCards: updatedCards.json,
  newCards: newCards.json,
  summary: {
    totalUpdated: updatedCards.json.length,
    totalNew: newCards.json.length,
    overdue: 0
  }
};

// Count overdue cards (due date passed)
const today = new Date();
activity.overdue = [...updatedCards.json, ...newCards.json]
  .filter(card => {
    if (!card.due) return false;
    return new Date(card.due) < today;
  });

activity.summary.overdue = activity.overdue.length;

// Format for AI
const formattedData = {
  date: activity.date,
  stats: activity.summary,
  newCards: activity.newCards.map(card => ({
    name: card.name,
    list: card.list?.name || 'Unknown',
    url: card.shortUrl
  })),
  updatedCards: activity.updatedCards.map(card => ({
    name: card.name,
    list: card.list?.name || 'Unknown',
    url: card.shortUrl,
    lastActivity: card.dateLastActivity
  })),
  overdueCards: activity.overdue.map(card => ({
    name: card.name,
    due: card.due,
    url: card.shortUrl
  }))
};

return { json: formattedData };
